#include<bits/stdc++.h>
using namespace std;
queue<int> q[14];
int cnt[14], life = 4, now = 13, ans = 0;
int v[14][4];
int main() {
	for (int i = 1; i <= 13; i++) {
		if (i != 13) {
			stack<int> s;
			for (int j = 1; j <= 4; j++) {
				char x;
				int x2;

				cin >> x;

				if (x == '0')x2 = 10;
				else if (x == 'J') x2 = 11;
				else if (x == 'Q') x2 = 12;
				else if (x == 'K') x2 = 13;
				else if (x == 'A') x2 = 1;
				else x2 = x - '0';
				s.push(x2);
			}
			for (int j = 1; j <= 4; j++) {
				int x = s.top();
				q[i].push(x);
				s.pop();
			}
		} else {
			for (int j = 1; j <= 4; j++) {
				char x;
				int x2;
				cin >> x;
				if (x == '0')x2 = 10;
				else if (x == 'J') x2 = 11;
				else if (x == 'Q') x2 = 12;
				else if (x == 'K') x2 = 13;
				else if (x == 'A') x2 = 1;
				else x2 = x - '0';
				q[13].push(x2);
			}
		}
	}
	while (life > 0) {

		int x = q[now].front();
		q[now].pop();
		v[now][cnt[now]++] = 1;
		if (x == 13) {
			life--;
			now = 13;
		} else {
			now = x;
		}
	}
	for (int i = 1; i <= 12; i++) {
		int flag = 1;
		for (int j = 0; j <= 3; j++) {
			if (v[i][j] != 1) {
				flag = 0;
				break;
			}
		}
		if (flag) {
			ans++;
		}
	}
	cout << ans;
	return 0;
}
